def subarraySum(nums, k):
    count = 0
    curr_sum = 0
    seen = {0: 1} # Base case: sum=0 seen once
    for n in nums:
        curr_sum += n
        if curr_sum - k in seen:
            count += seen[curr_sum - k]
        seen[curr_sum] = seen.get(curr_sum, 0) + 1
    return count

cppCode:
int subarraySum(vector<int>& nums, int k) {
    unordered_map<int, int> seen;
    seen[0] = 1;
    int curr_sum = 0, count = 0;
    for (int n : nums) {
        curr_sum += n;
        if (seen.count(curr_sum - k)) {
            count += seen[curr_sum - k];
        }
        seen[curr_sum]++;
    }
    return count;
}

