import random
class RandomizedCollection:
    def __init__(self):
        self.lst = []
        self.idx_map = {} # val -> set of indices

    def insert(self, val: int) -> bool:
        not_present = val not in self.idx_map
        if not_present:
            self.idx_map[val] = set()
        self.idx_map[val].add(len(self.lst))
        self.lst.append(val)
        return not_present

    def remove(self, val: int) -> bool:
        if val not in self.idx_map or not self.idx_map[val]:
            return False
        # Get an index of the value
        remove_idx = self.idx_map[val].pop()
        last_val = self.lst[-1]

        # Swap with last element
        self.lst[remove_idx] = last_val
        self.idx_map[last_val].add(remove_idx)
        self.idx_map[last_val].discard(len(self.lst) - 1)

        self.lst.pop()
        if not self.idx_map[val]:
            del self.idx_map[val]
        return True

    def getRandom(self) -> int:
        return random.choice(self.lst)

cppCode:
class RandomizedCollection {
    vector<int> lst;
    unordered_map<int, unordered_set<int>> idx_map;
public:
    RandomizedCollection() {}

    bool insert(int val) {
        bool not_present = idx_map[val].empty();
        idx_map[val].insert(lst.size());
        lst.push_back(val);
        return not_present;
    }

    bool remove(int val) {
        if (idx_map[val].empty()) return false;
        int remove_idx = *idx_map[val].begin();
        idx_map[val].erase(remove_idx);

        int last_val = lst.back();
        lst[remove_idx] = last_val;

        // Update indices
        idx_map[last_val].insert(remove_idx);
        idx_map[last_val].erase(lst.size() - 1);

        lst.pop_back();
        return true;
    }

    int getRandom() {
        return lst[rand() % lst.size()];
    }
};

